{
  "name": "Smart Credit Ledger",
  "description": "A mobile-first ledger application for managing vendor and customer payments, tracking credits, and cash flows."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ContactType = 'CUSTOMER' | 'SUPPLIER';

export interface Contact {
  id: string;
  name: string;
  phone: string;
  type: ContactType;
  balance: number; // Positive means "To Pay" (for suppliers) or "To Receive" (for customers)
  lastUpdated: string;
}

export type TransactionType = 'CREDIT' | 'PAYMENT';

export interface Transaction {
  id: string;
  contactId: string;
  date: string; // ISO string or formatted string
  description?: string;
  amount: number;
  type: TransactionType;
  balanceAfter: number;
  hasAttachment?: boolean;
}

export interface SummaryStats {
  toCollect: number;
  toPay: number;
}

import React from 'react';
import { BookText, Wallet, Receipt, UserCircle } from 'lucide-react';

export const BottomNav: React.FC = () => {
  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 py-2 px-6 flex justify-between items-center z-40 pb-safe">
      <div className="flex flex-col items-center text-blue-600 gap-1">
        <BookText size={20} />
        <span className="text-[10px] font-medium">Credit Book</span>
      </div>
      <div className="flex flex-col items-center text-gray-400 gap-1">
        <Wallet size={20} />
        <span className="text-[10px] font-medium">Cash Book</span>
      </div>
      <div className="flex flex-col items-center text-gray-400 gap-1">
        <Receipt size={20} />
        <span className="text-[10px] font-medium">Invoice</span>
      </div>
      <div className="flex flex-col items-center text-gray-400 gap-1">
        <UserCircle size={20} />
        <span className="text-[10px] font-medium">Profile</span>
      </div>
    </div>
  );
};

import React from 'react';
import { FileText } from 'lucide-react';
import { Transaction } from '../types';

interface TransactionRowProps {
  transaction: Transaction;
}

export const TransactionRow: React.FC<TransactionRowProps> = ({ transaction }) => {
  // Logic to determine color based on transaction type relative to a Supplier perspective
  // For Supplier: Payment reduces balance (Good/Green), Credit increases balance (Debt/Red)
  // This mimics the screenshot colors

  const isPayment = transaction.type === 'PAYMENT';

  return (
    <div className="bg-white p-4 border-b border-gray-100 flex flex-col gap-2">
      <div className="flex justify-between items-start">
        <span className="font-semibold text-sm text-slate-800">{transaction.date}</span>
        <span className={`font-bold text-sm ${isPayment ? 'text-green-700' : 'text-green-700'}`}>
          Rs. {transaction.amount.toLocaleString()}
        </span>
      </div>

      <div className="flex justify-between items-end">
        <div className="flex flex-col gap-1">
          {transaction.description && (
            <span className="text-xs text-gray-400 uppercase">{transaction.description}</span>
          )}
          {transaction.hasAttachment && (
            <div className="w-8 h-10 border border-gray-200 rounded flex items-center justify-center bg-gray-50 mt-1">
              <FileText size={14} className="text-gray-400" />
            </div>
          )}
        </div>

        <span className="text-xs text-gray-500">
          Bal. Rs.{transaction.balanceAfter.toLocaleString()}
        </span>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { 
  Users, 
  Truck, 
  Search, 
  BarChart3, 
  ChevronLeft, 
  MoreVertical, 
  Pencil, 
  PlayCircle,
  CalendarClock,
  ArrowDown,
  ArrowUp
} from 'lucide-react';
import { BottomNav } from './components/BottomNav';
import { TransactionRow } from './components/TransactionRow';
import { Contact, Transaction, ContactType } from './types';
import { MOCK_CONTACTS, MOCK_TRANSACTIONS } from './constants';

function App() {
  const [activeTab, setActiveTab] = useState<ContactType>('SUPPLIER');
  const [selectedContact, setSelectedContact] = useState<Contact | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Derived state
  const filteredContacts = useMemo(() => {
    return MOCK_CONTACTS.filter(c => 
      c.type === activeTab && 
      (c.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
       c.phone.includes(searchQuery))
    );
  }, [activeTab, searchQuery]);

  const totalToPay = useMemo(() => {
    return MOCK_CONTACTS
      .filter(c => c.type === 'SUPPLIER')
      .reduce((sum, c) => sum + c.balance, 0);
  }, []);

  const totalToCollect = useMemo(() => {
    return MOCK_CONTACTS
      .filter(c => c.type === 'CUSTOMER')
      .reduce((sum, c) => sum + c.balance, 0);
  }, []);

  const currentTransactions = useMemo(() => {
    if (!selectedContact) return [];
    return MOCK_TRANSACTIONS.filter(t => t.contactId === selectedContact.id);
  }, [selectedContact]);


  // View: Ledger Detail (Image 1 replica)
  if (selectedContact) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col pb-24 relative">
        {/* Header */}
        <header className="bg-white sticky top-0 z-30 shadow-sm px-4 py-3 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => setSelectedContact(null)} className="p-1">
              <ChevronLeft size={24} className="text-slate-800" />
            </button>
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center text-sm font-medium text-gray-600">
                {selectedContact.name.substring(0, 1)}
              </div>
              <h1 className="font-bold text-lg text-slate-800">{selectedContact.name}</h1>
              <button className="text-gray-400">
                <Pencil size={16} />
              </button>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button className="border border-slate-300 rounded px-2 py-1 text-xs font-semibold text-slate-700">
              Reports
            </button>
            <button>
              <MoreVertical size={20} className="text-slate-700" />
            </button>
          </div>
        </header>

        {/* Balance Summary */}
        <div className="p-4 bg-white mb-2">
          <div className="bg-gray-50 rounded-lg p-6 flex flex-col items-center justify-center">
            <h2 className="text-red-600 text-xl font-bold">Rs. {selectedContact.balance.toLocaleString()}</h2>
            <p className="text-gray-500 text-sm">To Pay</p>
          </div>
        </div>

        {/* Transactions List */}
        <div className="flex-1">
          {currentTransactions.length > 0 ? (
             currentTransactions.map(t => <TransactionRow key={t.id} transaction={t} />)
          ) : (
            <div className="p-8 text-center text-gray-400">No transactions found</div>
          )}
        </div>

        {/* Sticky Action Buttons */}
        <div className="fixed bottom-0 left-0 right-0 bg-white p-4 flex gap-4 border-t border-gray-200 z-50">
          <button className="flex-1 bg-red-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 active:bg-red-800 transition-colors">
            <ArrowDown size={18} />
            Get Credit
          </button>
          <button className="flex-1 bg-green-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 active:bg-green-800 transition-colors">
            <ArrowUp size={18} />
            Make Payment
          </button>
        </div>
      </div>
    );
  }

  // View: Dashboard (Image 2 replica)
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col pb-20">
      {/* Top Bar */}
      <header className="bg-white px-4 py-3 pb-0">
        <div className="flex justify-between items-start mb-4">
          <div>
            <h1 className="text-xl font-bold text-slate-800">Manage Credit</h1>
            <div className="flex items-center text-slate-600 text-sm gap-1 mt-1">
              <span>Smart Time</span>
              <ChevronLeft size={16} className="-rotate-90" />
            </div>
          </div>
          <div className="flex gap-4">
            <div className="flex flex-col items-center gap-0.5">
              <PlayCircle className="text-blue-600" size={22} />
              <span className="text-[10px] text-blue-600 font-medium">Demo</span>
            </div>
            <div className="flex flex-col items-center gap-0.5">
              <CalendarClock className="text-blue-600" size={22} />
              <span className="text-[10px] text-blue-600 font-medium">Reminders</span>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-200">
          <button 
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 relative ${activeTab === 'CUSTOMER' ? 'text-slate-800' : 'text-slate-500'}`}
            onClick={() => setActiveTab('CUSTOMER')}
          >
            <Users size={18} />
            Customers
            {activeTab === 'CUSTOMER' && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-slate-800"></div>
            )}
          </button>
          <button 
            className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 relative ${activeTab === 'SUPPLIER' ? 'text-slate-800' : 'text-slate-500'}`}
            onClick={() => setActiveTab('SUPPLIER')}
          >
            <Truck size={18} />
            Suppliers
            {activeTab === 'SUPPLIER' && (
              <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-slate-800"></div>
            )}
          </button>
        </div>
      </header>

      {/* Summary Cards */}
      <div className="p-4 flex gap-3">
        {activeTab === 'SUPPLIER' ? (
          <>
            <div className="flex-1 bg-green-50 border border-green-100 rounded-lg p-3">
              <p className="text-xs text-slate-600 mb-1">Supplier holds</p>
              <p className="text-lg font-bold text-green-700">Rs. 0</p>
            </div>
            <div className="flex-1 bg-red-50 border border-red-100 rounded-lg p-3">
              <p className="text-xs text-slate-600 mb-1">To pay</p>
              <p className="text-lg font-bold text-red-700">Rs. {totalToPay.toLocaleString()}</p>
            </div>
          </>
        ) : (
          <>
            <div className="flex-1 bg-green-50 border border-green-100 rounded-lg p-3">
              <p className="text-xs text-slate-600 mb-1">To Collect</p>
              <p className="text-lg font-bold text-green-700">Rs. {totalToCollect.toLocaleString()}</p>
            </div>
             {/* Placeholder for symmetry */}
             <div className="flex-1"></div>
          </>
        )}
      </div>

      {/* Search */}
      <div className="px-4 mb-2">
        <div className="bg-white border border-gray-200 rounded-lg flex items-center px-3 py-2.5">
          <Search size={18} className="text-gray-400 mr-2" />
          <input 
            type="text" 
            placeholder="Search name or number here" 
            className="flex-1 text-sm outline-none text-slate-700"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button className="border-l border-gray-200 pl-3 ml-1">
             <BarChart3 size={18} className="text-blue-500" />
          </button>
        </div>
      </div>

      {/* List Header */}
      <div className="px-4 py-2 flex justify-between items-center">
        <span className="text-xs font-medium text-gray-400 uppercase">
          {filteredContacts.length} {activeTab === 'SUPPLIER' ? 'Suppliers' : 'Customers'}
        </span>
        <span className="text-xs font-medium text-gray-400 uppercase">Amount (Rs.)</span>
      </div>

      {/* List */}
      <div className="flex-1 px-4 flex flex-col gap-2">
        {filteredContacts.map(contact => (
          <div 
            key={contact.id} 
            onClick={() => setSelectedContact(contact)}
            className="bg-white rounded-lg p-3 shadow-sm flex justify-between items-center active:bg-gray-50 transition-colors cursor-pointer"
          >
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center text-slate-600 font-medium">
                {contact.name.substring(0, 1)}
              </div>
              <div>
                <h3 className="text-sm font-semibold text-slate-800">{contact.name}</h3>
                <p className="text-xs text-gray-400 mt-0.5">{contact.phone}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[10px] text-gray-400 uppercase mb-0.5">
                {activeTab === 'SUPPLIER' ? 'To pay' : 'To collect'}
              </p>
              <p className={`font-bold ${activeTab === 'SUPPLIER' ? 'text-red-700' : 'text-green-700'}`}>
                {contact.balance.toLocaleString()}
              </p>
            </div>
          </div>
        ))}

        {filteredContacts.length === 0 && (
            <div className="text-center py-10 text-gray-400 text-sm">
                No contacts found.
            </div>
        )}
      </div>

      {/* Add Button */}
      <div className="px-4 mt-4">
        <button className="w-full bg-blue-600 text-white font-semibold py-3 rounded-lg shadow-md active:bg-blue-700 transition-colors">
          Add {activeTab === 'SUPPLIER' ? 'Supplier' : 'Customer'}
        </button>
      </div>

      {/* Spacer for Bottom Nav */}
      <div className="h-4"></div>

      <BottomNav />
    </div>
  );
}

export default App;

import React from 'react';
import { FileText } from 'lucide-react';
import { Transaction } from '../types';

interface TransactionRowProps {
  transaction: Transaction;
