        .reduce((sum, t) => sum + t.amount, 0);
    const totalPayment = currentTransactions
        .filter(t => t.type === 'PAYMENT')
        .reduce((sum, t) => sum + t.amount, 0);

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
