                    </div>
                    <ChevronRight size={16} className="text-gray-300" />
                  </div>
                )}

                {/* Hidden File Input */}
                <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept="image/*,application/pdf"
                    onChange={handleFileSelect}
