type ViewState = 'DASHBOARD' | 'DETAIL' | 'TRANSACTION_FORM' | 'EDIT_CONTACT' | 'REPORT' | 'PROFILE' | 'REMINDERS';
type ThemeColor = 'blue' | 'purple' | 'emerald' | 'orange' | 'dark';

// Theme Configuration
