    const themeColor = isCredit ? 'text-red-700' : 'text-green-700';
    const btnColor = isCredit ? 'bg-red-800' : 'bg-green-800';

    let titleAction = '';
    if (editingTransactionId) titleAction = 'Edit';
    else if (isRent) titleAction = isCredit ? 'Withdraw from' : 'Save to';
