    primary: 'bg-blue-600',
    primaryHover: 'hover:bg-blue-700',
    primaryActive: 'active:bg-blue-700',
    text: 'text-blue-600',
    textDark: 'text-blue-700',
    light: 'bg-blue-50',
    lightHover: 'hover:bg-blue-100',
    border: 'border-blue-200',
    bgIndicator: 'bg-blue-600'
  },
  purple: {
