                    />
                </div>

                {selectedContact.type === 'RENT' && (
                    <>
                        <div className="flex flex-col gap-2">
                            <label className="text-sm font-semibold text-slate-600">Target Amount</label>
                            <input 
                                type="number" 
                                value={newContactTarget}
