      const sortedTrans = [...reportTransactions].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      sortedTrans.forEach(t => {
          const credit = t.type === 'CREDIT' ? t.amount.toLocaleString() : "-";
