          const rowData = [
              t.date,
              t.description || "-",
              credit,
              payment,
              t.balanceAfter.toLocaleString()
          ];
          tableRows.push(rowData);
      });

      autoTable(doc, {
          head: [tableColumn],
          body: tableRows,
          startY: 95,
          theme: 'grid',
          styles: { fontSize: 9 },
          headStyles: { fillColor: [66, 66, 66] }
      });

      doc.save(`Statement_${selectedContact.name}_${reportMonth || 'All'}.pdf`);
