            </button>
            <button 
                onClick={() => setCurrentView('REPORT')}
                className={`flex items-center gap-1 ${theme.light} ${theme.lightHover} px-3 py-1.5 rounded-full text-xs font-semibold ${theme.text} transition-colors`}
            >
                <FileText size={14} />
                Reports
